sql:
SELECT AVG(CAST(budget AS REAL)) AS average_budget
FROM projects
WHERE status = 'Open' AND region = 'NDjamena';

external_knowledge:
- 'top-notch feedback' refers to a rating of at least 4 out of 5; 
- 'large beneficiary base' refers to more than 5000 people; 
- 'highest rated' means the project with the highest average rating given by users.

